@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (IconContent is not null)
    {
        <div class="mb-4 inline-flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10 text-primary">
            @IconContent
        </div>
    }
    @if (!string.IsNullOrEmpty(Title))
    {
        <h3 class="text-lg font-semibold text-foreground">@Title</h3>
    }
    @if (!string.IsNullOrEmpty(Description))
    {
        <p class="mt-2 text-sm text-muted-foreground">@Description</p>
    }
    @ChildContent
</div>

@code {
    [Parameter] public string? Title { get; set; }
    [Parameter] public string? Description { get; set; }

    /// <summary>
    /// The icon slot rendered in the leading badge. Named <c>IconContent</c>
    /// (not <c>Icon</c>) so the <see cref="Lumeo.Icon"/> component can be used
    /// freely inside it — a parameter called <c>Icon</c> shadowed the component
    /// type, turning <c>&lt;Icon&gt;</c> into the slot rather than the icon (#300).
    /// </summary>
    [Parameter] public RenderFragment? IconContent { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex flex-col", Class);
}
